package com.example.grpc;

import io.grpc.Server;
import io.grpc.ServerBuilder;
import io.grpc.ServerInterceptor;
import io.grpc.Metadata;
import io.grpc.ServerCall;
import io.grpc.ServerCallHandler;
import io.grpc.ForwardingServerCall;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import javax.sql.DataSource;
import com.zaxxer.hikari.HikariConfig;
import com.zaxxer.hikari.HikariDataSource;

import java.io.IOException;
import java.util.concurrent.TimeUnit;

public class GrpcServer {
    private static final Logger logger = LoggerFactory.getLogger(GrpcServer.class);
    
    private Server server;
    
    public void start(int port, boolean isProduction) throws IOException {
        DataSource dataSource = createSecureDataSource();
        DatabaseConnectionPool dbPool = new DatabaseConnectionPoolImpl(dataSource);
        
        SecureUserServiceImpl userService = new SecureUserServiceImpl(dbPool, isProduction);
        
        server = ServerBuilder.forPort(port)
            .addService(userService)
            .intercept(new SecurityHeaderInterceptor())
            .intercept(new RateLimitInterceptor())
            .maxInboundMessageSize(1024 * 1024)
            .build()
            .start();
            
        logger.info("gRPC server started on port {}", port);
        
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            logger.info("Shutting down gRPC server");
            try {
                GrpcServer.this.stop();
            } catch (InterruptedException e) {
                logger.error("Error during shutdown", e);
            }
        }));
    }
    
    public void stop() throws InterruptedException {
        if (server != null) {
            server.shutdown().awaitTermination(30, TimeUnit.SECONDS);
        }
    }
    
    public void blockUntilShutdown() throws InterruptedException {
        if (server != null) {
            server.awaitTermination();
        }
    }
    
    private DataSource createSecureDataSource() {
        HikariConfig config = new HikariConfig();
        config.setJdbcUrl(System.getenv("DB_URL"));
        config.setUsername(System.getenv("DB_USERNAME"));
        config.setPassword(System.getenv("DB_PASSWORD"));
        config.setMaximumPoolSize(10);
        config.setMinimumIdle(2);
        config.setConnectionTimeout(30000);
        config.setIdleTimeout(600000);
        config.setMaxLifetime(1800000);
        config.setAutoCommit(true);
        config.addDataSourceProperty("useSSL", "true");
        config.addDataSourceProperty("requireSSL", "true");
        config.addDataSourceProperty("verifyServerCertificate", "true");
        
        return new HikariDataSource(config);
    }
    
    public static void main(String[] args) throws IOException, InterruptedException {
        String environment = System.getenv("ENVIRONMENT");
        boolean isProduction = "production".equalsIgnoreCase(environment);
        
        int port = Integer.parseInt(System.getenv().getOrDefault("GRPC_PORT", "50051"));
        
        GrpcServer server = new GrpcServer();
        server.start(port, isProduction);
        server.blockUntilShutdown();
    }
}

class SecurityHeaderInterceptor implements ServerInterceptor {
    private static final Logger logger = LoggerFactory.getLogger(SecurityHeaderInterceptor.class);
    
    @Override
    public <ReqT, RespT> ServerCall.Listener<ReqT> interceptCall(
            ServerCall<ReqT, RespT> call,
            Metadata headers,
            ServerCallHandler<ReqT, RespT> next) {
        
        return next.startCall(new ForwardingServerCall.SimpleForwardingServerCall<ReqT, RespT>(call) {
            @Override
            public void sendHeaders(Metadata headers) {
                headers.put(Metadata.Key.of("X-Content-Type-Options", Metadata.ASCII_STRING_MARSHALLER), "nosniff");
                headers.put(Metadata.Key.of("X-Frame-Options", Metadata.ASCII_STRING_MARSHALLER), "DENY");
                headers.put(Metadata.Key.of("Strict-Transport-Security", Metadata.ASCII_STRING_MARSHALLER), 
                    "max-age=31536000; includeSubDomains");
                super.sendHeaders(headers);
            }
        }, headers);
    }
}

class RateLimitInterceptor implements ServerInterceptor {
    private static final Logger logger = LoggerFactory.getLogger(RateLimitInterceptor.class);
    private final java.util.concurrent.ConcurrentHashMap<String, java.util.concurrent.atomic.AtomicInteger> requestCounts = 
        new java.util.concurrent.ConcurrentHashMap<>();
    
    @Override
    public <ReqT, RespT> ServerCall.Listener<ReqT> interceptCall(
            ServerCall<ReqT, RespT> call,
            Metadata headers,
            ServerCallHandler<ReqT, RespT> next) {
        
        String clientId = call.getAttributes().get(io.grpc.Grpc.TRANSPORT_ATTR_REMOTE_ADDR).toString();
        
        java.util.concurrent.atomic.AtomicInteger count = requestCounts.computeIfAbsent(
            clientId, k -> new java.util.concurrent.atomic.AtomicInteger(0));
        
        if (count.incrementAndGet() > 100) {
            call.close(io.grpc.Status.RESOURCE_EXHAUSTED.withDescription("Rate limit exceeded"), new Metadata());
            return new ServerCall.Listener<ReqT>() {};
        }
        
        return next.startCall(call, headers);
    }
}